      }
    }).catch(err => {
       console.error("Auth check failed", err);
       setCurrentView('login');
    }).finally(() => clearTimeout(safetyTimer));

    // 2. Listen for Auth Changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) {
        fetchProfile(session.user.id);
        loadLocalData(session.user.id);
        setCurrentView('home');
      } else {
        // CLEAN UP DATA ON LOGOUT TO PREVENT LEAKS
        setHistory([]);
        setSavedClients([]);
        setSavedProducts([]);
        setCompanySettings({ name: '', address: '', contact: '', nuit: '', logo: '', defaultTaxRate: 16, currency: 'MZN', language: 'pt', theme: 'light', plan: 'FREE', isAdmin: false });
        setCurrentView('login');
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const loadLocalData = (userId: string) => {
    if (!userId) return;
    const loadedHistory = getHistory(userId);
    setHistory(loadedHistory);
    setSavedClients(getSavedClients(userId));
    setSavedProducts(getSavedProducts(userId));

    // Also try to load local settings as fallback
    const localSettings = getCompanySettings(userId);
    if (localSettings) {
        setCompanySettings(prev => ({...prev, ...localSettings}));
    }
  };

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (data) {
        setCompanySettings(prev => ({
          ...prev,
          name: data.company_name || '',
          address: data.address || '',
          contact: data.contact || '',
          nuit: data.nuit || '',
          logo: data.logo || '',
          currency: data.currency || 'MZN',
          language: data.language || 'pt',
          theme: (data.theme as any) || 'light',
          plan: data.plan || 'FREE',
          isAdmin: data.is_admin || false
        }));
      }
    } catch (e) {
      console.error("Profile fetch error", e);
    }
  };

  // --- Theme Effect ---
  useEffect(() => {
    if (companySettings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [companySettings.theme]);

  // --- Auto Save Settings Effect (Sync with Supabase) ---
  useEffect(() => {
     if (companySettings.name && session?.user?.id) {
        saveCompanySettings(companySettings, session.user.id);

        supabase.from('profiles').upsert({
            id: session.user.id,
            company_name: companySettings.name,
            address: companySettings.address,
            contact: companySettings.contact,
            nuit: companySettings.nuit,
            logo: companySettings.logo,
            currency: companySettings.currency,
            language: companySettings.language,
            theme: companySettings.theme,
            // plan is handled by payment webhook/admin usually
        }).then(({ error }) => {
            if (error) console.error("Error syncing profile", error);
        });
     }
  }, [companySettings, session]);

  // --- Calculation Effect ---
  useEffect(() => {
    const subtotal = formData.items.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = (subtotal * (formData.taxRate / 100));
    const total = Math.max(0, subtotal + taxAmount - formData.discount);
    setFormData(prev => ({ ...prev, subtotal, taxAmount, total }));
  }, [formData.items, formData.taxRate, formData.discount]);

  // --- Actions: Document Logic ---
  const initNewDocument = (type: DocumentType) => {
    if (!session?.user?.id) return;

    if (companySettings.plan === 'FREE') {
      const canCreate = checkDailyLimit(session.user.id);
      if (!canCreate) {
        notify("Limite diário de 10 documentos atingido no plano Grátis.", 'info');
        setShowPricingModal(true);
        return;
      }
    }

    const today = new Date().toISOString().split('T')[0];
    const dateObj = new Date(); dateObj.setDate(dateObj.getDate() + 15);

    let stamp = 'PAGO';
    if (type === 'INVOICE') stamp = 'EMITIDO';
    if (type === 'QUOTE') stamp = 'PENDENTE';

    setFormData({
      ...InitialReceipt,
      id: crypto.randomUUID(),
      type,
      number: generateNextReceiptNumber(history, type),
      date: today,
      dueDate: type === 'INVOICE' || type === 'QUOTE' ? dateObj.toISOString().split('T')[0] : undefined,
      items: [],
      taxRate: type === 'INVOICE' ? companySettings.defaultTaxRate || 0 : 0,
      stampText: stamp,
      currency: companySettings.currency,
      language: companySettings.language,
      companyName: companySettings.name,
      companyAddress: companySettings.address,
      companyContact: companySettings.contact,
      companyNuit: companySettings.nuit,
      companyLogo: companySettings.logo,
    });
    setMobileTab('editor');
    setCurrentView('app');
  };

  const handleConvertQuote = () => {
    if (formData.type !== 'QUOTE') return;
    const newNumber = generateNextReceiptNumber(history, 'INVOICE');
    setFormData(prev => ({
      ...prev,
      type: 'INVOICE',
      number: newNumber,
      stampText: 'EMITIDO',
      taxRate: companySettings.defaultTaxRate || 0
    }));
    notify(`Convertido para Fatura #${newNumber}`, 'success');
  };

  const handleSave = (silent = false) => {
    if (!session?.user?.id) {
        notify("Sessão expirada. Faça login novamente.", 'error');
        return;
    }
    if (!formData.clientName) {
      notify(t('client') + ' obrigatório', 'error');
      return;
    }
    if (formData.items.length === 0) {
      notify(t('items') + ' obrigatório', 'error');
      return;
    }
    const newHistory = saveReceipt(formData, session.user.id);
    setHistory(newHistory);
    setSavedClients(getSavedClients(session.user.id));
    setSavedProducts(getSavedProducts(session.user.id));

    if (!silent) notify("Documento salvo com sucesso!", 'success');
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'clientName') {
       const matchedClient = savedClients.find(c => c.name.toLowerCase() === value.toLowerCase());
       if (matchedClient) {
         setFormData(prev => ({
           ...prev,
           clientName: value,
           clientContact: matchedClient.contact || prev.clientContact,
           clientNuit: matchedClient.nuit || prev.clientNuit,
           clientLocation: matchedClient.location || prev.clientLocation
         }));
         return;
       }
    }

    setFormData(prev => ({ ...prev, [name]: (name === 'taxRate' || name === 'discount') ? parseFloat(value) || 0 : value }));
  };

  const handleNewItemChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    if (name === 'description') {
       const matchedProduct = savedProducts.find(p => p.description.toLowerCase() === value.toLowerCase());
       if (matchedProduct) {
          setNewItem(prev => ({ ...prev, description: value, unitPrice: matchedProduct.unitPrice }));
          return;
       }
       setNewItem(p => ({ ...p, description: value }));
    } else {
       setNewItem(p => ({ ...p, [name]: parseFloat(value) || 0 }));
    }
  };

  const handleClearClient = () => {
    setFormData(prev => ({
      ...prev,
      clientName: '',
      clientContact: '',
      clientLocation: '',
      clientNuit: ''
    }));
    notify("Campos do cliente limpos", 'info');
  };

  const addItem = () => {
    if (!newItem.description) return;
    const qty = newItem.quantity || 1;
    const price = newItem.unitPrice || 0;
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: crypto.randomUUID(), description: newItem.description!, quantity: qty, unitPrice: price, total: qty * price }]
    }));
    setNewItem({ description: '', quantity: 1, unitPrice: 0 });
  };

  const handleGeneratePDF = async () => {
    if (!receiptRef.current || !window.html2canvas || !window.jspdf) {
        notify("Recursos de PDF não prontos. Aguarde...", 'info');
        return;
    }

    setIsGeneratingPdf(true);
    notify("Gerando PDF...", 'info');

    try {
      // Small delay to ensure rendering of the hidden element
      await new Promise(r => setTimeout(r, 200)); 

      const canvas = await window.html2canvas(receiptRef.current, { 
          scale: 2, 
          useCORS: true, 
          logging: false,
          allowTaint: true,
          backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new window.jspdf.jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`${formData.number || 'documento'}.pdf`);

      // Save silently if session active
      if (session?.user?.id) {
          handleSave(true); 
      }
      notify("PDF baixado com sucesso!", 'success');
    } catch (error: any) {
      console.error("PDF Gen Error:", error);
      notify(`Erro ao gerar PDF: ${error.message || 'Tente novamente'}`, 'error');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const handleShare = () => {
    const text = `Biz-flow: ${formData.type} ${formData.number} - ${fMoney(formData.total)}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
  };

  const handleSelectPlan = (plan: SubscriptionPlan) => {
    // This is now handled inside PricingModal opening PaymentModal
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password: pass });
    setAuthLoading(false);
    if (error) {
        notify(error.message, 'error');
    } else {
        notify("Bem-vindo de volta!", 'success');
    }
  };

  const handleGoogleLogin = async () => {
    setAuthLoading(true);
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: 'https://ilukexelmihfdezbgcrp.supabase.co/auth/v1/callback'
      }
    });
    if (error) {
       setAuthLoading(false);
       notify(error.message, 'error');
    }
  };

  const handleRegister = async (email: string, pass: string, data: any) => {
    setAuthLoading(true);
    const { data: authData, error: authError } = await supabase.auth.signUp({ email, password: pass });

    if (authError) {
        setAuthLoading(false);
        notify(authError.message, 'error');
        return;
    }

    if (authData.user) {
        const { error: profileError } = await supabase.from('profiles').insert({
            id: authData.user.id,
            company_name: data.companyName,
            logo: data.logo,
            currency: data.currency,
            language: data.language
        });

        if (profileError) {
            console.error("Profile creation error", profileError);
            notify("Conta criada, mas houve erro ao salvar perfil.", 'info');
        } else {
            notify("Conta criada com sucesso! Bem-vindo ao Biz-flow.", 'success');
        }
        setAuthLoading(false);
    }
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      localStorage.removeItem('bizflow_session');
      // State is cleared in onAuthStateChange listener
      notify("Sessão encerrada.", 'info');
  };

  const handleSettingsLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setCompanySettings(prev => ({ ...prev, logo: reader.result as string }));
        notify("Logo carregado!", 'success');
      };
      reader.readAsDataURL(file);
    }
  };

  // --- Canvas Signature Logic ---
  const startDrawing = (e: any) => {
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    isDrawing.current = true;
    const { x, y } = getCoords(e);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };
  const draw = (e: any) => {
    if (!isDrawing.current) return;
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y);
    ctx.stroke();
  };
  const stopDrawing = () => { isDrawing.current = false; canvasRef.current?.getContext('2d')?.beginPath(); };
  const getCoords = (e: any) => {
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return { x: clientX - rect.left, y: clientY - rect.top };
  };
  const saveSig = () => {
    setFormData(p => ({ ...p, signatureData: canvasRef.current?.toDataURL() }));
    setShowSignatureModal(false);
    notify("Assinatura salva", 'success');
  };

  const toggleTheme = () => {
    setCompanySettings(prev => {
        const newTheme: 'light' | 'dark' = prev.theme === 'dark' ? 'light' : 'dark';
        const newSettings: CompanySettings = { ...prev, theme: newTheme } as CompanySettings;
        return newSettings;
    });
  };

  // --- RENDER ---

  if (currentView === 'loading') {
    return <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex items-center justify-center"><i className="fa-solid fa-circle-notch animate-spin text-4xl text-blue-600"></i></div>;
  }

  if (currentView === 'admin') {
     return <AdminDashboard onClose={() => setCurrentView('home')} />;
  }

  if (['login', 'register', 'forgotPassword'].includes(currentView)) {
    return (
      <AuthScreens 
        view={currentView as any} 
        setView={setCurrentView as any} 
        onLogin={handleLogin} 
        onRegister={handleRegister} 
        onGoogleLogin={handleGoogleLogin} 
        isLoading={authLoading} 
      />
    );
  }

  return (
    <>
      {currentView === 'home' ? (
        <Dashboard 
          history={history} companySettings={companySettings} 
          onLogout={handleLogout}
          onNewDocument={initNewDocument}
          onOpenSettings={() => setShowSettingsModal(true)}
          onLoadDocument={(doc) => { setFormData(doc); setCurrentView('app'); setMobileTab('preview'); }}
          onViewHistory={() => { setCurrentView('app'); }}
          onToggleTheme={toggleTheme}
          t={t}
          userId={session?.user?.id || ''}
          onOpenPricing={() => setShowPricingModal(true)} 
        />
      ) : (
        /* App View (Split Screen) */
        <div className="min-h-screen bg-slate-100 dark:bg-slate-950 flex flex-col h-screen overflow-hidden transition-colors duration-500 animate-fadeIn">
           <header className="bg-white dark:bg-slate-900 h-16 flex-none shadow-sm z-30 border-b border-slate-200 dark:border-slate-800 relative">
              <div className="max-w-[1600px] mx-auto px-4 h-full flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <button onClick={() => setCurrentView('home')} className="text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors w-8 h-8 flex items-center justify-center rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                       <i className="fa-solid fa-arrow-left"></i>
                    </button>
                    <div className="flex items-center gap-3 border-l border-slate-200 dark:border-slate-700 pl-4">
                        <span className="font-bold tracking-tight text-slate-900 dark:text-white">{formData.number}</span>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-wider ${formData.type === 'INVOICE' ? 'bg-blue-100 text-blue-700' : formData.type === 'QUOTE' ? 'bg-purple-100 text-purple-700' : 'bg-emerald-100 text-emerald-700'}`}>{formData.type}</span>
                    </div>
                 </div>
                 <div className="flex gap-3">
                    <button onClick={() => setShowSettingsModal(true)} className="w-9 h-9 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition hover:bg-slate-100 dark:hover:bg-slate-800 flex items-center justify-center"><i className="fa-solid fa-gear"></i></button>
                    <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 self-center mx-1"></div>
                    <button onClick={() => handleSave()} className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-1.5 rounded-lg text-sm font-bold transition shadow-lg shadow-blue-600/20 flex items-center gap-2">
                       <i className="fa-solid fa-save"></i> <span className="hidden sm:inline">{t('save')}</span>
                    </button>
                    <button onClick={handleGeneratePDF} disabled={isGeneratingPdf} className="bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-5 py-1.5 rounded-lg text-sm font-bold hover:bg-slate-800 dark:hover:bg-slate-100 transition shadow-lg shadow-slate-900/10 flex items-center gap-2">
                       {isGeneratingPdf ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-download"></i>} <span className="hidden sm:inline">PDF</span>
                    </button>
                 </div>
              </div>
           </header>
           <div className="md:hidden bg-white dark:bg-slate-900 border-b dark:border-slate-800 flex flex-none z-20">
              <button onClick={() => setMobileTab('editor')} className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider border-b-2 transition-colors ${mobileTab === 'editor' ? 'border-blue-600 text-blue-600 dark:text-blue-400' : 'border-transparent text-slate-500 dark:text-slate-400'}`}>Editor</button>
              <button onClick={() => setMobileTab('preview')} className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider border-b-2 transition-colors ${mobileTab === 'preview' ? 'border-blue-600 text-blue-600 dark:text-blue-400' : 'border-transparent text-slate-500 dark:text-slate-400'}`}>Visualizar</button>
           </div>
           <div className="flex-grow flex overflow-hidden max-w-[1600px] mx-auto w-full">
              <div className={`w-full md:w-[450px] lg:w-[500px] bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex-none overflow-y-auto scrollbar-thin ${mobileTab === 'preview' ? 'hidden md:block' : 'block animate-fadeIn'}`}>
                 <div className="p-6 pb-24">
                    <EditorForm 
                       formData={formData} onChange={handleInputChange} 
                       newItem={newItem} onNewItemChange={handleNewItemChange}
                       onAddItem={addItem} onRemoveItem={(id) => setFormData(p => ({...p, items: p.items.filter(i => i.id !== id)}))}
                       onEnhanceDescription={async () => { setIsEnhancing(true); const res = await improveDescription(newItem.description || ''); setNewItem(p => ({...p, description: res})); setIsEnhancing(false); }}
                       isEnhancing={isEnhancing} t={t} fMoney={fMoney}
                       onInitNew={initNewDocument} onSign={() => setShowSignatureModal(true)}
                       statusOptions={['PAGO', 'EMITIDO', 'PENDENTE', 'VENCIDO', 'ANULADO']}
                       onClearClient={handleClearClient}
                       savedClients={savedClients} savedProducts={savedProducts}
                       onConvertQuote={handleConvertQuote}
                    />
                 </div>
              </div>
              <div className={`flex-grow bg-slate-100 dark:bg-slate-950 overflow-y-auto flex justify-center p-4 md:p-10 ${mobileTab === 'editor' ? 'hidden md:flex' : 'flex animate-fadeIn'}`}>
                 <div className="relative w-full max-w-[210mm] flex flex-col items-center">
                    <div className="hidden md:block shadow-[0_30px_60px_-15px_rgba(0,0,0,0.3)] transition-transform hover:scale-[1.01] duration-500">
                        {/* Desktop View - Visual Only (No Ref) */}
                        <DocumentPreview data={formData} />
                    </div>
                    {/* Mobile Only Preview - Visual Only (No Ref) */}
                    <div className="md:hidden w-full overflow-hidden rounded-lg shadow-2xl mb-8 ring-1 ring-black/5">
                        <div className="origin-top transform scale-[0.45] xs:scale-[0.55] sm:scale-[0.65]" style={{ height: '1300px', marginBottom: '-1100px' }}>
                            <DocumentPreview data={formData} />
                        </div>
                    </div>
                    <div className="md:hidden fixed bottom-6 right-6 flex flex-col gap-3 z-50">
                       <button onClick={handleShare} className="w-14 h-14 bg-[#25D366] text-white rounded-full shadow-xl shadow-green-900/20 flex items-center justify-center text-2xl hover:scale-110 transition active:scale-90"><i className="fa-brands fa-whatsapp"></i></button>
                       <button onClick={handleGeneratePDF} className="w-14 h-14 bg-blue-600 text-white rounded-full shadow-xl shadow-blue-900/20 flex items-center justify-center text-xl hover:scale-110 transition active:scale-90"><i className="fa-solid fa-download"></i></button>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

       {/* --- GLOBAL MODALS --- */}

       {showPricingModal && (
         <PricingModal 
           currentPlan={companySettings.plan} 
           onClose={() => setShowPricingModal(false)} 
           onSelectPlan={handleSelectPlan}
           userEmail={session?.user?.email} 
           userName={companySettings.name}
         />
       )}

       {showSignatureModal && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[60] flex items-center justify-center p-4 animate-fadeIn">
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border dark:border-slate-800 animate-scaleIn">
               <div className="p-4 bg-slate-50 dark:bg-slate-800 border-b dark:border-slate-700 flex justify-between items-center">
                  <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2"><i className="fa-solid fa-pen-nib"></i> Assinar Documento</h3>
                  <button onClick={() => setShowSignatureModal(false)} className="w-8 h-8 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 flex items-center justify-center text-slate-500"><i className="fa-solid fa-times"></i></button>
               </div>
               <div className="h-48 bg-white cursor-crosshair touch-none relative">
                   <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-slate-100 text-4xl font-black uppercase opacity-40 tracking-widest">Área de Assinatura</div>
                   <canvas ref={canvasRef} width={400} height={192} className="w-full h-full"
                      onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                      onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing}
                   />
               </div>
               <div className="p-4 border-t dark:border-slate-700 bg-slate-50 dark:bg-slate-900 flex justify-between">
                   <button onClick={() => { const ctx = canvasRef.current?.getContext('2d'); ctx?.clearRect(0,0,400,200); }} className="text-slate-500 dark:text-slate-400 text-sm font-bold hover:text-red-500 dark:hover:text-red-400 transition">Limpar</button>
                   <button onClick={saveSig} className="bg-slate-900 dark:bg-blue-600 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 dark:hover:bg-blue-700 shadow-lg">Confirmar</button>
               </div>
            </div>
         </div>
       )}

       {showSettingsModal && (
         <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[60] flex items-end md:items-center justify-center md:p-4 animate-fadeIn">
             <div className="bg-white dark:bg-slate-900 w-full md:max-w-lg md:rounded-3xl rounded-t-3xl shadow-2xl max-h-[90vh] overflow-y-auto animate-slideUp border dark:border-slate-800">
                 <div className="p-6 border-b dark:border-slate-800 sticky top-0 bg-white/95 dark:bg-slate-900/95 z-10 flex justify-between items-center backdrop-blur">
                     <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2"><i className="fa-solid fa-sliders"></i> Configurações</h2>
                     <button onClick={() => setShowSettingsModal(false)} className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition"><i className="fa-solid fa-times"></i></button>
                 </div>

                 <div className="p-6 space-y-8">

                     {/* ADMIN ACCESS BUTTON (Visible only if admin) */}
                     {session && companySettings.isAdmin && (
                       <button onClick={() => { setShowSettingsModal(false); setCurrentView('admin'); }} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-slate-800 transition">
                          <i className="fa-solid fa-shield-halved"></i> Acessar Painel Admin
                       </button>
                     )}

                     {/* Theme Toggle */}
