import { ReceiptData, CompanySettings, DocumentType, Comment, Transaction, SavedClient, SavedProduct } from '../types';

const STORAGE_KEY = 'bizflow_receipts_v1';
const SETTINGS_KEY = 'bizflow_settings_v1';
const COMMENTS_KEY = 'bizflow_comments_v1';
const TRANSACTIONS_KEY = 'bizflow_transactions_v1';
const CLIENTS_KEY = 'bizflow_clients_db';
const PRODUCTS_KEY = 'bizflow_products_db';

// --- HELPER: USER ISOLATION ---
// This ensures that data is saved specific to the logged-in user ID
const getUserKey = (baseKey: string, userId: string): string => {
  if (!userId) return baseKey; // Fallback only if absolutely necessary, but app should enforce ID
  return `${baseKey}_${userId}`;
};

// --- DATABASE / AUTOCOMPLETE HELPERS ---

export const getSavedClients = (userId: string): SavedClient[] => {
  if (!userId) return [];
  try {
    const stored = localStorage.getItem(getUserKey(CLIENTS_KEY, userId));
    return stored ? JSON.parse(stored) : [];
  } catch { return []; }
};

export const getSavedProducts = (userId: string): SavedProduct[] => {
  if (!userId) return [];
  try {
    const stored = localStorage.getItem(getUserKey(PRODUCTS_KEY, userId));
    return stored ? JSON.parse(stored) : [];
  } catch { return []; }
};

const learnClient = (doc: ReceiptData, userId: string) => {
  if (!doc.clientName || !userId) return;
  const clients = getSavedClients(userId);
  const exists = clients.find(c => c.name.toLowerCase() === doc.clientName.toLowerCase());

  if (!exists) {
    const newClient: SavedClient = {
      name: doc.clientName,
      contact: doc.clientContact,
      nuit: doc.clientNuit,
      location: doc.clientLocation
    };
    localStorage.setItem(getUserKey(CLIENTS_KEY, userId), JSON.stringify([...clients, newClient]));
  }
};

const learnProducts = (doc: ReceiptData, userId: string) => {
  if (!userId) return;
  const products = getSavedProducts(userId);
  let updated = false;

  doc.items.forEach(item => {
    if (!item.description) return;
    const exists = products.find(p => p.description.toLowerCase() === item.description.toLowerCase());
    if (!exists) {
      products.push({ description: item.description, unitPrice: item.unitPrice });
      updated = true;
    }
  });

  if (updated) {
    localStorage.setItem(getUserKey(PRODUCTS_KEY, userId), JSON.stringify(products));
  }
};


// --- MAIN SAVE FUNCTION ---

export const saveReceipt = (receipt: ReceiptData, userId: string): ReceiptData[] => {
  if (!userId) return [];
  const existing = getHistory(userId);
  // Check if update or new
  const index = existing.findIndex(r => r.id === receipt.id);
  let newHistory;

  if (index >= 0) {
    newHistory = [...existing];
    newHistory[index] = receipt;
  } else {
    newHistory = [receipt, ...existing];
  }

  localStorage.setItem(getUserKey(STORAGE_KEY, userId), JSON.stringify(newHistory));

  // Trigger Learning
  learnClient(receipt, userId);
  learnProducts(receipt, userId);

  return newHistory;
};

export const getHistory = (userId: string): ReceiptData[] => {
  if (!userId) return [];
  const stored = localStorage.getItem(getUserKey(STORAGE_KEY, userId));
  if (!stored) return [];
  try {
    const data = JSON.parse(stored);
    // Migration helper for old data if necessary
    return data.map((item: any) => ({
       ...item,
       type: item.type || 'RECEIPT', // Default old items to Receipt
       items: item.items || (item.description ? [{
         id: 'legacy',
         description: item.description,
         quantity: item.quantity || 1,
         unitPrice: item.unitPrice || 0,
         total: (item.quantity || 1) * (item.unitPrice || 0)
       }] : []),
       subtotal: item.subtotal || item.total,
       taxRate: item.taxRate || 0,
       taxAmount: item.taxAmount || 0,
       discount: item.discount || 0
    }));
  } catch (e) {
    console.error("Error parsing history", e);
    return [];
  }
};

// --- LIMIT CHECKER FOR FREE PLAN ---
export const checkDailyLimit = (userId: string): boolean => {
  if (!userId) return false;
  const history = getHistory(userId);
  const today = new Date().toISOString().split('T')[0];

  // Filter documents created today
  const createdToday = history.filter(doc => doc.date === today);

  // Limit is 10 per day for FREE plan
  return createdToday.length < 10;
};

export const generateNextReceiptNumber = (history: ReceiptData[], type: DocumentType): string => {
  let prefix = 'REC';
  if (type === 'INVOICE') prefix = 'FAT';
  if (type === 'QUOTE') prefix = 'COT';

  // Filter history by type to find the last number for this specific document type
  const typeHistory = history.filter(h => (h.type || 'RECEIPT') === type);

  if (typeHistory.length === 0) return `${prefix}-0001`;

  // Find max number based on the string sort
  const latest = typeHistory[0].number; 

  try {
    const parts = latest.split('-');
    if (parts.length === 2) {
      const num = parseInt(parts[1], 10);
      const next = num + 1;
      return `${prefix}-${next.toString().padStart(4, '0')}`;
    }
  } catch (e) {
    // Fallback
  }
  return `${prefix}-${(typeHistory.length + 1).toString().padStart(4, '0')}`;
};

