type ViewState = 'login' | 'register' | 'home' | 'app' | 'forgotPassword' | 'loading' | 'admin';

const App: React.FC = () => {
  // --- Global State ---
  const [currentView, setCurrentView] = useState<ViewState>('loading'); // Start loading
  const [history, setHistory] = useState<ReceiptData[]>([]);
  const [companySettings, setCompanySettings] = useState<CompanySettings>({
    name: '', address: '', contact: '', nuit: '', logo: '', defaultTaxRate: 16, currency: 'MZN', language: 'pt', theme: 'light', plan: 'FREE', isAdmin: false
  });

  // --- Autocomplete Data ---
  const [savedClients, setSavedClients] = useState<SavedClient[]>([]);
  const [savedProducts, setSavedProducts] = useState<SavedProduct[]>([]);

  // --- Editor State ---
  const [formData, setFormData] = useState<ReceiptData>(InitialReceipt);
  const [newItem, setNewItem] = useState<Partial<LineItem>>({ description: '', quantity: 1, unitPrice: 0 });
  const [isEnhancing, setIsEnhancing] = useState(false);

  // --- UI State ---
  const [mobileTab, setMobileTab] = useState<'editor' | 'preview'>('editor');
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSignatureModal, setShowSignatureModal] = useState(false);
  const [showPricingModal, setShowPricingModal] = useState(false);
  const [authLoading, setAuthLoading] = useState(false);
  const [session, setSession] = useState<any>(null);

  // --- Refs & Hooks ---
  const receiptRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const isDrawing = useRef(false);
  const { notify } = useToast(); 

  // --- Helpers ---
  const t = (key: any) => getTranslation(companySettings.language, key);
  const fMoney = (val: number) => formatMoney(val, companySettings.currency);

  // --- Initialization & Auth Check ---
  useEffect(() => {
    // 0. CHECK PAYMENT RETURN (Legacy Check)
    const checkPaymentReturn = async () => {
       const params = new URLSearchParams(window.location.search);
       const referencia = params.get('referencia') || params.get('idpay') || params.get('transaction_id');

       if (referencia) {
           notify("Verificando pagamento...", "info");
           window.history.replaceState({}, document.title, window.location.pathname);

           const status = await checkPaymentStatus(referencia);
           if (status === 'SUCCESS') {
               notify("Pagamento confirmado! Plano PRO ativado.", "success");
               setCompanySettings(prev => {
                   const updated = { ...prev, plan: 'PRO' as SubscriptionPlan };
                   if (session?.user?.id) saveCompanySettings(updated, session.user.id);
                   return updated;
               });
               if (session) {
                 supabase.from('profiles').update({ plan: 'PRO' }).eq('id', session.user.id);
               }
           }
       }
    };

    checkPaymentReturn();

    // Safety Timeout
    const safetyTimer = setTimeout(() => {
       setCurrentView((prev) => prev === 'loading' ? 'login' : prev);
    }, 5000);

    // 1. Check Supabase Session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) {
        fetchProfile(session.user.id);
        loadLocalData(session.user.id); // Load data specific to this user
        setCurrentView('home');
      } else {
        setCurrentView('login');
      }
    }).catch(err => {
       console.error("Auth check failed", err);
       setCurrentView('login');
    }).finally(() => clearTimeout(safetyTimer));

    // 2. Listen for Auth Changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) {
        fetchProfile(session.user.id);
        loadLocalData(session.user.id); // Load data specific to this user
        setCurrentView('home');
      } else {
        // --- CRITICAL: CLEAR DATA ON LOGOUT ---
        setHistory([]);
        setSavedClients([]);
        setSavedProducts([]);
        setCompanySettings({ name: '', address: '', contact: '', nuit: '', logo: '', defaultTaxRate: 16, currency: 'MZN', language: 'pt', theme: 'light', plan: 'FREE', isAdmin: false });
        setCurrentView('login');
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const loadLocalData = (userId: string) => {
    if (!userId) return;
    const loadedHistory = getHistory(userId);
    setHistory(loadedHistory);
    setSavedClients(getSavedClients(userId));
    setSavedProducts(getSavedProducts(userId));

    // Also try to load local settings as fallback
    const localSettings = getCompanySettings(userId);
    if (localSettings) {
        setCompanySettings(prev => ({...prev, ...localSettings}));
    }
  };

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (data) {
        setCompanySettings(prev => ({
          ...prev,
          name: data.company_name || '',
          address: data.address || '',
          contact: data.contact || '',
          nuit: data.nuit || '',
          logo: data.logo || '',
          currency: data.currency || 'MZN',
          language: data.language || 'pt',
          theme: (data.theme as any) || 'light',
          plan: data.plan || 'FREE',
          isAdmin: data.is_admin || false
        }));
      }
    } catch (e) {
      console.error("Profile fetch error", e);
    }
  };

  // --- Theme Effect ---
  useEffect(() => {
    if (companySettings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [companySettings.theme]);

  // --- Auto Save Settings Effect (Sync with Supabase) ---
  useEffect(() => {
     if (companySettings.name && session?.user?.id) {
        saveCompanySettings(companySettings, session.user.id);

        supabase.from('profiles').upsert({
            id: session.user.id,
            company_name: companySettings.name,
            address: companySettings.address,
            contact: companySettings.contact,
            nuit: companySettings.nuit,
            logo: companySettings.logo,
            currency: companySettings.currency,
            language: companySettings.language,
            theme: companySettings.theme,
            // plan is handled by payment webhook/admin usually
        }).then(({ error }) => {
            if (error) console.error("Error syncing profile", error);
        });
     }
  }, [companySettings, session]);

  // --- Calculation Effect ---
  useEffect(() => {
    const subtotal = formData.items.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = (subtotal * (formData.taxRate / 100));
    const total = Math.max(0, subtotal + taxAmount - formData.discount);
    setFormData(prev => ({ ...prev, subtotal, taxAmount, total }));
  }, [formData.items, formData.taxRate, formData.discount]);

  // --- Actions: Document Logic ---
  const initNewDocument = (type: DocumentType) => {
    if (!session?.user?.id) return;

    if (companySettings.plan === 'FREE') {
      // Check limit for this specific user
      const canCreate = checkDailyLimit(session.user.id);
      if (!canCreate) {
        notify("Limite diário de 10 documentos atingido no plano Grátis.", 'info');
        setShowPricingModal(true);
        return;
      }
    }

    const today = new Date().toISOString().split('T')[0];
    const dateObj = new Date(); dateObj.setDate(dateObj.getDate() + 15);

    let stamp = 'PAGO';
    if (type === 'INVOICE') stamp = 'EMITIDO';
    if (type === 'QUOTE') stamp = 'PENDENTE';

    setFormData({
      ...InitialReceipt,
      id: crypto.randomUUID(),
      type,
      number: generateNextReceiptNumber(history, type),
      date: today,
      dueDate: type === 'INVOICE' || type === 'QUOTE' ? dateObj.toISOString().split('T')[0] : undefined,
      items: [],
      taxRate: type === 'INVOICE' ? companySettings.defaultTaxRate || 0 : 0,
      stampText: stamp,
      currency: companySettings.currency,
      language: companySettings.language,
      companyName: companySettings.name,
      companyAddress: companySettings.address,
      companyContact: companySettings.contact,
      companyNuit: companySettings.nuit,
      companyLogo: companySettings.logo,
    });
    setMobileTab('editor');
    setCurrentView('app');
  };

  const handleConvertQuote = () => {
    if (formData.type !== 'QUOTE') return;
    const newNumber = generateNextReceiptNumber(history, 'INVOICE');
    setFormData(prev => ({
      ...prev,
      type: 'INVOICE',
      number: newNumber,
      stampText: 'EMITIDO',
      taxRate: companySettings.defaultTaxRate || 0
    }));
    notify(`Convertido para Fatura #${newNumber}`, 'success');
  };

  const handleSave = (silent = false) => {
    if (!session?.user?.id) {
        notify("Sessão expirada. Faça login novamente.", 'error');
        return;
    }
    if (!formData.clientName) {
      notify(t('client') + ' obrigatório', 'error');
      return;
    }
    if (formData.items.length === 0) {
      notify(t('items') + ' obrigatório', 'error');
      return;
    }

    // Save to specific user storage
    const newHistory = saveReceipt(formData, session.user.id);
    setHistory(newHistory);
    setSavedClients(getSavedClients(session.user.id));
    setSavedProducts(getSavedProducts(session.user.id));

    if (!silent) notify("Documento salvo com sucesso!", 'success');
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'clientName') {
       const matchedClient = savedClients.find(c => c.name.toLowerCase() === value.toLowerCase());
       if (matchedClient) {
         setFormData(prev => ({
           ...prev,
           clientName: value,
           clientContact: matchedClient.contact || prev.clientContact,
           clientNuit: matchedClient.nuit || prev.clientNuit,
           clientLocation: matchedClient.location || prev.clientLocation
         }));
         return;
       }
    }

    setFormData(prev => ({ ...prev, [name]: (name === 'taxRate' || name === 'discount') ? parseFloat(value) || 0 : value }));
  };

  const handleNewItemChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    if (name === 'description') {
       const matchedProduct = savedProducts.find(p => p.description.toLowerCase() === value.toLowerCase());
       if (matchedProduct) {
          setNewItem(prev => ({ ...prev, description: value, unitPrice: matchedProduct.unitPrice }));
          return;
       }
       setNewItem(p => ({ ...p, description: value }));
    } else {
       setNewItem(p => ({ ...p, [name]: parseFloat(value) || 0 }));
    }
  };

  const handleClearClient = () => {
    setFormData(prev => ({
      ...prev,
      clientName: '',
      clientContact: '',
      clientLocation: '',
      clientNuit: ''
    }));
    notify("Campos do cliente limpos", 'info');
  };

  const addItem = () => {
    if (!newItem.description) return;
    const qty = newItem.quantity || 1;
    const price = newItem.unitPrice || 0;
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: crypto.randomUUID(), description: newItem.description!, quantity: qty, unitPrice: price, total: qty * price }]
    }));
    setNewItem({ description: '', quantity: 1, unitPrice: 0 });
  };

  const handleGeneratePDF = async () => {
    if (!receiptRef.current || !window.html2canvas || !window.jspdf) {
        notify("Recursos de PDF não prontos. Aguarde...", 'info');
        return;
    }

    setIsGeneratingPdf(true);
    notify("Gerando PDF...", 'info');

    try {
      // Small delay to ensure rendering of the hidden element
      await new Promise(r => setTimeout(r, 200)); 

      const canvas = await window.html2canvas(receiptRef.current, { 
          scale: 2, 
          useCORS: true, 
          logging: false,
          allowTaint: true,
          backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new window.jspdf.jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`${formData.number || 'documento'}.pdf`);

      // Save silently if session active
      if (session?.user?.id) {
          handleSave(true); 
      }
      notify("PDF baixado com sucesso!", 'success');
    } catch (error: any) {
      console.error("PDF Gen Error:", error);
      notify(`Erro ao gerar PDF: ${error.message || 'Tente novamente'}`, 'error');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const handleShare = () => {
    const text = `Biz-flow: ${formData.type} ${formData.number} - ${fMoney(formData.total)}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
  };

  const handleSelectPlan = (plan: SubscriptionPlan) => {
    // This is now handled inside PricingModal opening PaymentModal
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password: pass });
    setAuthLoading(false);
    if (error) {
        notify(error.message, 'error');
    } else {
        notify("Bem-vindo de volta!", 'success');
    }
  };

  const handleGoogleLogin = async () => {
    setAuthLoading(true);
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: 'https://ilukexelmihfdezbgcrp.supabase.co/auth/v1/callback'
      }
    });
    if (error) {
       setAuthLoading(false);
       notify(error.message, 'error');
    }
  };

  const handleRegister = async (email: string, pass: string, data: any) => {
    setAuthLoading(true);
    const { data: authData, error: authError } = await supabase.auth.signUp({ email, password: pass });

    if (authError) {
        setAuthLoading(false);
        notify(authError.message, 'error');
        return;
    }

    if (authData.user) {
        const { error: profileError } = await supabase.from('profiles').insert({
            id: authData.user.id,
            company_name: data.companyName,
            logo: data.logo,
            currency: data.currency,
            language: data.language
        });

        if (profileError) {
            console.error("Profile creation error", profileError);
            notify("Conta criada, mas houve erro ao salvar perfil.", 'info');
        } else {
            notify("Conta criada com sucesso! Bem-vindo ao Biz-flow.", 'success');
        }
        setAuthLoading(false);
    }
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      localStorage.removeItem('bizflow_session');
      notify("Sessão encerrada.", 'info');
      // State clear handled by onAuthStateChange listener
  };

  const handleSettingsLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setCompanySettings(prev => ({ ...prev, logo: reader.result as string }));
        notify("Logo carregado!", 'success');
      };
      reader.readAsDataURL(file);
    }
  };

  // --- Canvas Signature Logic ---
  const startDrawing = (e: any) => {
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    isDrawing.current = true;
    const { x, y } = getCoords(e);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };
  const draw = (e: any) => {
    if (!isDrawing.current) return;
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y);
    ctx.stroke();
  };
  const stopDrawing = () => { isDrawing.current = false; canvasRef.current?.getContext('2d')?.beginPath(); };
  const getCoords = (e: any) => {
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return { x: clientX - rect.left, y: clientY - rect.top };
  };
  const saveSig = () => {
    setFormData(p => ({ ...p, signatureData: canvasRef.current?.toDataURL() }));
    setShowSignatureModal(false);
    notify("Assinatura salva", 'success');
  };

  const toggleTheme = () => {
    setCompanySettings(prev => {
        const newTheme: 'light' | 'dark' = prev.theme === 'dark' ? 'light' : 'dark';
        const newSettings: CompanySettings = { ...prev, theme: newTheme } as CompanySettings;
        return newSettings;
    });
  };

  // --- RENDER ---

  if (currentView === 'loading') {
    return <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex items-center justify-center"><i className="fa-solid fa-circle-notch animate-spin text-4xl text-blue-600"></i></div>;
  }

  if (currentView === 'admin') {
