             <div className="bg-white dark:bg-slate-900 w-full md:max-w-lg md:rounded-3xl rounded-t-3xl shadow-2xl max-h-[90vh] overflow-y-auto animate-slideUp border dark:border-slate-800">
                 <div className="p-6 border-b dark:border-slate-800 sticky top-0 bg-white/95 dark:bg-slate-900/95 z-10 flex justify-between items-center backdrop-blur">
