                       </button>

                       <button onClick={onOpenPricing} className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 hover:border-yellow-300 hover:bg-yellow-50 dark:hover:bg-slate-800 transition-all flex items-center gap-3 group shadow-sm">
                          <div className="w-10 h-10 rounded-full bg-yellow-100 dark:bg-yellow-900/30 text-yellow-500 flex items-center justify-center group-hover:scale-110 transition-transform"><i className="fa-solid fa-crown"></i></div>
