const CACHE_NAME = 'bizflow-v1';
const DYNAMIC_CACHE = 'bizflow-dynamic-v1';

// Arquivos essenciais para carregar a "casca" do app imediatamente
const STATIC_ASSETS = [
  '/',
  '/index.html',
  '/manifest.json',
  '/logo.svg',
  '/index.tsx'
];

// Instalação: Cache dos arquivos estáticos iniciais
self.addEventListener('install', (event) => {
  self.skipWaiting(); // Força o SW a ativar imediatamente
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      console.log('[Service Worker] Caching static assets');
      return cache.addAll(STATIC_ASSETS);
    })
  );
});

// Ativação: Limpeza de caches antigos
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.map((key) => {
          if (key !== CACHE_NAME && key !== DYNAMIC_CACHE) {
            return caches.delete(key);
          }
        })
      );
    })
  );
  return self.clients.claim();
});

// Interceptação de Requisições (Fetch)
self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // 1. Ignorar requisições para o Supabase (Dados dinâmicos)
  // Deixamos o app lidar com dados offline via localStorage ou lógica interna
  if (url.hostname.includes('supabase.co')) {
    return;
  }

  // 2. Estratégia Stale-While-Revalidate para arquivos estáticos e CDNs
  // (Tenta servir do cache rápido, mas atualiza em segundo plano)
  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      const fetchPromise = fetch(event.request)
        .then((networkResponse) => {
          // Se a resposta for válida, salva no cache dinâmico (para CDNs como Tailwind, FontAwesome, etc.)
          if (networkResponse && networkResponse.status === 200 && networkResponse.type === 'basic' || networkResponse.type === 'cors') {
            const responseToCache = networkResponse.clone();
            caches.open(DYNAMIC_CACHE).then((cache) => {
              cache.put(event.request, responseToCache);
            });
          }
          return networkResponse;
        })
        .catch(() => {
          // Se falhar a rede e não tiver cache (Offline total pela primeira vez)
          // Poderíamos retornar uma página offline aqui
        });

      // Retorna o cache se existir, senão espera a rede
      return cachedResponse || fetchPromise;
    })
  );
});

